arguments.argument:
if variable_local_exists("spriteChange")
{
  newSprite=spriteChange
  if newSprite=1
  {
    sprite_index=sInvisibleSolidMask
    image_xscale=4
    for(i=0;i<4;i+=1)
    {
      bColUp[i]=1
      lineColor[i]=i*63
    }
  }
  else if newSprite=2 or newSprite=3
  {
    sprite_index=sInvisibleSolidMask
    image_xscale=4
  }
}
